const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// =============================================================================\n// Prime Tech Gallery — schema.prisma (v4.0 — Dual-Database Architecture)\n// PostgreSQL + Prisma ORM\n//\n// ARCHITECTURE NOTE:\n// This database is the SECURE OPERATIONAL CORE. It stores users, auth, sensitive\n// inventory (IMEIs, costs), transactions, and suppliers.\n//\n// Product catalog (names, specs, images, search) lives in the Catalog Engine\n// (MongoDB + Meilisearch). The two systems are linked via `catalog_id`, which\n// is the MongoDB _id of the product document (e.g. \"6a0cbd95da32579c61b5b1b8\").\n//\n// The `CatalogRef` model is a lightweight read-only cache of key catalog fields.\n// It exists solely for SQL reporting and joins — it is NOT the source of truth.\n// The Catalog Engine always wins. Sync it via POST /v1/admin/catalog-ref/sync.\n// =============================================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================================\n// ENUMS\n// =============================================================================\n\nenum Role {\n  SUPER_ADMIN // Can do everything including manage other ADMINs\n  ADMIN // Full CRUD on products, inventory, reports\n  SALESMAN // POS access only — no pricing edits, no cost visibility\n  CUSTOMER // Web storefront access\n}\n\nenum InventoryStatus {\n  AVAILABLE // On shelf, ready to sell\n  SOLD // Linked to a completed SaleItem\n  DEFECTIVE // Failed QC or returned broken\n  RETURNED // Customer-returned, pending inspection\n  RESERVED // Held for a pending web order (future use)\n}\n\nenum UnitCondition {\n  NEW // Factory sealed\n  OPEN_BOX // Opened but unused\n  REFURBISHED // Tested and restored\n}\n\nenum PaymentMethod {\n  CASH\n  CARD\n  MOBILE_BANKING // bKash, Nagad, Rocket, etc.\n  BANK_TRANSFER\n}\n\nenum SaleSource {\n  POS // In-store, processed by a Salesman\n  WEB // Online order, self-service\n}\n\nenum SaleStatus {\n  PENDING // Web order placed, not yet paid\n  PAID // Payment confirmed\n  PROCESSING // Preparing for shipment (web only)\n  SHIPPED // Dispatched (web only)\n  COMPLETED // Delivered / POS transaction done\n  CANCELLED\n  REFUNDED\n}\n\nenum AddressType {\n  SHIPPING\n  BILLING\n}\n\nenum WarrantyStatus {\n  ACTIVE\n  EXPIRED\n  CLAIMED // A warranty service has been initiated\n  VOID // Voided due to damage/tampering\n}\n\n// =============================================================================\n// SECTION 1 — USERS & RBAC\n// The complete identity layer. Handles customers, staff, and admins.\n// =============================================================================\n\nmodel User {\n  id                      String    @id @default(uuid()) @db.Uuid\n  email                   String    @unique\n  password_hash           String // Argon2id — never store plaintext\n  name                    String\n  phone                   String?   @unique\n  image_url               String? // CDN URL for profile picture\n  role                    Role      @default(CUSTOMER)\n  is_active               Boolean   @default(true) // Soft-disable accounts without deleting\n  is_verified             Boolean   @default(false) // Email verification flag\n  verification_expires_at DateTime?\n  last_login_at           DateTime?\n  created_at              DateTime  @default(now())\n  updated_at              DateTime  @updatedAt\n\n  /// JSONB bucket for non-queryable fluid data only.\n  /// e.g. { \"ui_preferences\": { \"theme\": \"dark\" }, \"notification_settings\": { \"sms\": true } }\n  /// DO NOT store cart, wishlist, or addresses here — use relational tables.\n  metadata Json? @db.JsonB\n\n  // Relations\n  addresses         Address[]\n  sales_as_buyer    Sale[]           @relation(\"BuyerSales\")\n  sales_as_salesman Sale[]           @relation(\"SalesmanSales\")\n  refresh_tokens    RefreshToken[]\n  audit_logs        AuditLog[]\n  cart_items        CartItem[]\n  wishlist_items    WishlistItem[]\n  inventory_batches InventoryBatch[] // Admin who recorded the purchase batch\n  otp_codes         OtpCode[]\n\n  @@index([email])\n  @@index([phone])\n  @@index([role])\n  @@map(\"users\")\n}\n\nmodel Address {\n  id      String      @id @default(uuid()) @db.Uuid\n  user_id String      @db.Uuid\n  type    AddressType @default(SHIPPING)\n\n  label       String? // \"Home\", \"Office\", etc.\n  recipient   String\n  phone       String\n  line_1      String\n  line_2      String?\n  city        String\n  district    String\n  division    String?\n  postal_code String?\n  country     String  @default(\"Bangladesh\")\n  is_default  Boolean @default(false)\n\n  created_at DateTime @default(now())\n\n  user  User   @relation(fields: [user_id], references: [id], onDelete: Cascade)\n  sales Sale[] // A web order references a shipping address\n\n  @@index([user_id])\n  @@map(\"addresses\")\n}\n\n// =============================================================================\n// SECTION 2 — AUTHENTICATION & SECURITY\n// =============================================================================\n\nmodel RefreshToken {\n  id         String   @id @default(uuid()) @db.Uuid\n  user_id    String   @db.Uuid\n  token_hash String   @unique // SHA-256 hash of the raw token. NEVER store raw.\n  expires_at DateTime\n  revoked    Boolean  @default(false)\n  ip_address String? // IP that issued this token\n  user_agent String? // Browser/client that issued this token\n  created_at DateTime @default(now())\n\n  user User @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@index([user_id])\n  @@index([expires_at]) // For cleanup jobs: DELETE FROM refresh_tokens WHERE expires_at < NOW()\n  @@map(\"refresh_tokens\")\n}\n\n/// Immutable event log. Records every sensitive action across the system.\n/// Written by audit.service.ts. Never deleted. Grow-only table.\nmodel AuditLog {\n  id       String @id @default(uuid()) @db.Uuid\n  actor_id String @db.Uuid\n  action   String\n  // Action naming convention: RESOURCE_VERB\n  // Examples: IMEI_VIEWED, INVENTORY_UNIT_CREATED, SALE_COMPLETED,\n  //           USER_ROLE_CHANGED, BATCH_DELETED, CATALOG_REF_SYNCED\n\n  target_table String // e.g. \"inventory_units\", \"sales\", \"users\"\n  target_id    String // UUID of the affected record (String for flexibility)\n  metadata     Json?    @db.JsonB // { before: {...}, after: {...} } snapshot\n  ip_address   String?\n  created_at   DateTime @default(now())\n\n  actor User @relation(fields: [actor_id], references: [id])\n\n  @@index([actor_id])\n  @@index([action])\n  @@index([target_table, target_id])\n  @@index([created_at])\n  @@map(\"audit_logs\")\n}\n\n// =============================================================================\n// SECTION 3 — CATALOG REFERENCE (PostgreSQL Mirror of MongoDB Catalog Engine)\n//\n// WHY THIS EXISTS:\n// The Catalog Engine (MongoDB) is the source of truth for all product data.\n// However, SQL reports (e.g. \"top 5 products by revenue\") need to JOIN inventory\n// and sales data with a product name — without making HTTP calls to MongoDB at\n// query time. This table caches the minimum fields needed for reporting.\n//\n// SYNC RULE:\n// - Populated/updated when a product is created or updated in the Catalog Engine.\n// - Never edited directly via admin UI. Edit in Catalog Engine first, then sync.\n// - `catalog_id` is the MongoDB _id string — the universal link between both DBs.\n// =============================================================================\n\nmodel CatalogRef {\n  id String @id @default(uuid()) @db.Uuid\n\n  /// The MongoDB _id from the Catalog Engine. The universal foreign key.\n  /// Example: \"6a0cbd95da32579c61b5b1b8\"\n  catalog_id String @unique\n\n  // Cached fields — for reporting and human-readable joins only\n  sku        String  @unique\n  name       String\n  brand      String\n  category   String // category.primary from Catalog Engine\n  retail_mrp Decimal @db.Decimal(12, 2) // Cached MRP for reference\n\n  synced_at DateTime @default(now()) @updatedAt\n  // Last sync from Catalog Engine. If stale, treat as potentially outdated.\n\n  // Relations\n  inventory_units InventoryUnit[]\n  cart_items      CartItem[]\n  wishlist_items  WishlistItem[]\n\n  @@index([brand])\n  @@index([category])\n  @@index([catalog_id])\n  @@map(\"catalog_refs\")\n}\n\n// =============================================================================\n// SECTION 4 — SUPPLIERS & PURCHASE BATCHES\n//\n// Supplier = vendor (distributor, importer, brand rep).\n// InventoryBatch = one purchase event from one supplier (one invoice).\n// All units bought on the same invoice belong to the same batch.\n// This gives a full paper trail: who sold what, when, and at what cost.\n// =============================================================================\n\nmodel Supplier {\n  id           String   @id @default(uuid()) @db.Uuid\n  name         String\n  phone        String?\n  email        String?\n  company_name String?\n  address      String?\n  notes        String?  @db.Text\n  is_active    Boolean  @default(true)\n  created_at   DateTime @default(now())\n  updated_at   DateTime @updatedAt\n\n  batches InventoryBatch[]\n\n  @@index([name])\n  @@map(\"suppliers\")\n}\n\n/// One purchase event = one InventoryBatch.\n/// Groups all units bought together on a single invoice from a single supplier.\nmodel InventoryBatch {\n  id             String @id @default(uuid()) @db.Uuid\n  supplier_id    String @db.Uuid\n  recorded_by_id String @db.Uuid // The Admin who entered this batch\n\n  invoice_number String // Supplier's invoice/bill number\n  purchase_date  DateTime // Date of actual purchase (not created_at)\n  total_cost     Decimal? @db.Decimal(14, 2) // Total invoice value (for reconciliation)\n  currency       String   @default(\"BDT\")\n  notes          String?  @db.Text // e.g. \"Customs cleared at Chittagong port\"\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  supplier    Supplier        @relation(fields: [supplier_id], references: [id])\n  recorded_by User            @relation(fields: [recorded_by_id], references: [id])\n  units       InventoryUnit[]\n\n  @@unique([supplier_id, invoice_number]) // One invoice number per supplier\n  @@index([supplier_id])\n  @@index([purchase_date])\n  @@map(\"inventory_batches\")\n}\n\n// =============================================================================\n// SECTION 5 — THE VAULT (Secure Inventory)\n//\n// One InventoryUnit = one physical box in the showroom.\n// Sensitive fields (IMEI, serial) are AES-256-GCM encrypted at application layer.\n// Hash fields (HMAC-SHA256) allow fast barcode scan lookups without decrypting.\n//\n// CRITICAL: dealer_cost is ADMIN-only. The service layer must NEVER select\n// this field for SALESMAN or CUSTOMER scoped queries.\n// =============================================================================\n\nmodel InventoryUnit {\n  id String @id @default(uuid()) @db.Uuid\n\n  /// FK to CatalogRef — links this physical unit to its catalog product.\n  /// Use catalog_ref.catalog_id to call the Catalog Engine API.\n  catalog_ref_id String @db.Uuid\n\n  /// FK to the purchase batch this unit arrived with.\n  batch_id String? @db.Uuid\n\n  // ── Sensitive hardware identifiers ────────────────────────────────────────\n  // AES-256-GCM encrypted at application layer (encryption.service.ts).\n  // Raw plaintext NEVER enters this database.\n  imei_1        String? @unique // Ciphertext (primary IMEI)\n  imei_2        String? @unique // Ciphertext (secondary IMEI / dual-SIM)\n  serial_number String? @unique // Ciphertext\n  mac_address   String? // Not sensitive, stored plain\n\n  // ── Deterministic HMAC-SHA256 hashes ─────────────────────────────────────\n  // For barcode scan lookups. Same plaintext + secret always produces same hash.\n  // See security.service.ts → hashField()\n  imei_1_hash String? @unique\n  imei_2_hash String? @unique\n  serial_hash String? @unique\n\n  // ── Financials (ADMIN-only) ───────────────────────────────────────────────\n  dealer_cost Decimal @db.Decimal(12, 2) // What we paid (purchase price)\n\n  // ── Physical state ────────────────────────────────────────────────────────\n  status    InventoryStatus @default(AVAILABLE)\n  condition UnitCondition   @default(NEW)\n  notes     String?         @db.Text // e.g. \"Box slightly dented\"\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  // Relations\n  catalog_ref CatalogRef      @relation(fields: [catalog_ref_id], references: [id])\n  batch       InventoryBatch? @relation(fields: [batch_id], references: [id])\n  sale_item   SaleItem? // 1:1 — sold exactly once, ever\n  warranty    Warranty? // 1:1 — warranty issued at point of sale\n\n  @@index([catalog_ref_id])\n  @@index([batch_id])\n  @@index([status])\n  @@index([catalog_ref_id, status]) // \"How many iPhone 17 Pro Maxes are AVAILABLE?\"\n  @@index([imei_1_hash])\n  @@index([imei_2_hash])\n  @@index([serial_hash])\n  @@map(\"inventory_units\")\n}\n\n// =============================================================================\n// SECTION 6 — CART & WISHLIST\n// =============================================================================\n\n/// Server-side cart for authenticated CUSTOMERS only.\n/// Guest/POS carts are client-side (Zustand) and never persisted here.\nmodel CartItem {\n  id             String   @id @default(uuid()) @db.Uuid\n  user_id        String   @db.Uuid\n  catalog_ref_id String   @db.Uuid\n  quantity       Int      @default(1)\n  added_at       DateTime @default(now())\n\n  user        User       @relation(fields: [user_id], references: [id], onDelete: Cascade)\n  catalog_ref CatalogRef @relation(fields: [catalog_ref_id], references: [id])\n\n  @@unique([user_id, catalog_ref_id]) // One row per product per user. UPDATE quantity instead of INSERT.\n  @@map(\"cart_items\")\n}\n\nmodel WishlistItem {\n  id             String   @id @default(uuid()) @db.Uuid\n  user_id        String   @db.Uuid\n  catalog_ref_id String   @db.Uuid\n  added_at       DateTime @default(now())\n\n  user        User       @relation(fields: [user_id], references: [id], onDelete: Cascade)\n  catalog_ref CatalogRef @relation(fields: [catalog_ref_id], references: [id])\n\n  @@unique([user_id, catalog_ref_id])\n  @@map(\"wishlist_items\")\n}\n\n// =============================================================================\n// SECTION 7 — TRANSACTIONS & SALES\n// =============================================================================\n\nmodel Sale {\n  id                  String  @id @default(uuid()) @db.Uuid\n  buyer_id            String? @db.Uuid // Null for walk-in POS guests\n  salesman_id         String? @db.Uuid // Null for web self-service orders\n  shipping_address_id String? @db.Uuid // Only populated for web orders\n\n  total_amount   Decimal       @db.Decimal(12, 2)\n  discount_total Decimal       @default(0) @db.Decimal(12, 2)\n  tax_total      Decimal       @default(0) @db.Decimal(12, 2)\n  payment_method PaymentMethod\n  source         SaleSource\n  status         SaleStatus    @default(PENDING)\n\n  /// Walk-in POS guest info. Null when buyer_id is set.\n  /// Shape: { \"name\": \"Rahim Uddin\", \"phone\": \"01712345678\" }\n  customer_info Json? @db.JsonB\n\n  /// Payment gateway reference ID (bKash TrxID, SSLCommerz val_id, etc.)\n  payment_reference String?\n\n  notes String? @db.Text\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  buyer            User?      @relation(\"BuyerSales\", fields: [buyer_id], references: [id])\n  salesman         User?      @relation(\"SalesmanSales\", fields: [salesman_id], references: [id])\n  shipping_address Address?   @relation(fields: [shipping_address_id], references: [id])\n  items            SaleItem[]\n\n  @@index([buyer_id])\n  @@index([salesman_id])\n  @@index([status])\n  @@index([source])\n  @@index([created_at])\n  @@map(\"sales\")\n}\n\n/// One SaleItem = one physical box sold.\n/// @unique on inventory_unit_id is the most critical constraint in the entire system.\n/// It makes it IMPOSSIBLE at the database level to sell the same IMEI twice —\n/// even if there is a bug in application logic.\nmodel SaleItem {\n  id                String @id @default(uuid()) @db.Uuid\n  sale_id           String @db.Uuid\n  inventory_unit_id String @unique @db.Uuid // ONE UNIT. ONE SALE. FOREVER.\n\n  unit_price  Decimal  @db.Decimal(12, 2) // MRP snapshot at time of sale\n  discount    Decimal  @default(0) @db.Decimal(12, 2)\n  tax         Decimal  @default(0) @db.Decimal(12, 2)\n  sale_price  Decimal  @db.Decimal(12, 2) // unit_price - discount + tax\n  dealer_cost Decimal? @db.Decimal(12, 2) // Cost snapshot (ADMIN only)\n  profit      Decimal? @db.Decimal(12, 2) // sale_price - dealer_cost\n\n  sale           Sale          @relation(fields: [sale_id], references: [id])\n  inventory_unit InventoryUnit @relation(fields: [inventory_unit_id], references: [id])\n  warranty       Warranty?\n\n  @@index([sale_id])\n  @@map(\"sale_items\")\n}\n\n// =============================================================================\n// SECTION 8 — WARRANTY TRACKING\n//\n// Every smartphone/device sold gets a warranty record.\n// Linked to both the physical unit (InventoryUnit) and the sale line (SaleItem).\n// =============================================================================\n\nmodel Warranty {\n  id                String @id @default(uuid()) @db.Uuid\n  inventory_unit_id String @unique @db.Uuid // 1:1\n  sale_item_id      String @unique @db.Uuid // 1:1\n\n  duration_months Int // e.g. 12 for a 1-year warranty\n  starts_at       DateTime       @default(now())\n  expires_at      DateTime // starts_at + duration_months (calculated in service layer)\n  warrantor       String // e.g. \"Apple International\", \"Prime Tech Gallery\"\n  status          WarrantyStatus @default(ACTIVE)\n  notes           String?        @db.Text\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  inventory_unit InventoryUnit @relation(fields: [inventory_unit_id], references: [id])\n  sale_item      SaleItem      @relation(fields: [sale_item_id], references: [id])\n\n  @@index([expires_at]) // \"Show me all warranties expiring this month\"\n  @@index([status])\n  @@map(\"warranties\")\n}\n\n// =============================================================================\n// OTP CODES (Email verification & password reset)\n// =============================================================================\nmodel OtpCode {\n  id         String   @id @default(uuid()) @db.Uuid\n  user_id    String   @db.Uuid\n  code_hash  String // SHA-256 hash of the 6-digit OTP\n  type       OtpType // what this OTP is for\n  expires_at DateTime\n  used       Boolean  @default(false)\n  created_at DateTime @default(now())\n\n  user User @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@index([user_id])\n  @@index([expires_at])\n  @@map(\"otp_codes\")\n}\n\nenum OtpType {\n  EMAIL_VERIFICATION\n  PASSWORD_RESET\n}\n"
}

